const tokenize = (text) => (String(text || '').match(/[\u4e00-\u9fff]{2}|[a-zA-Z0-9-]{2,}/g) || []).map((token) => token.toLowerCase());
const stop = new Set(['推薦', '怎麼', '完整', '指南', 'the', 'and', 'for', 'with']);
const classifyTheme = (text) => {
  const source = String(text || '');
  if (/價格|費用|資費|price|cheap/i.test(source)) return 'pricing';
  if (/比較|評比|review|compare/i.test(source)) return 'comparison';
  if (/速度|流量|網速|吃到飽|speed|data/i.test(source)) return 'features';
  if (/學生|家庭|新手|family|student/i.test(source)) return 'audience';
  return 'general';
};
const organic = ($json.organic_results || []).slice(0, 10);
return organic.map((row, index) => {
  const text = [row.title, row.snippet || row.description || ''].join(' ');
  const counts = new Map();
  tokenize(text).forEach((token) => {
    if (!stop.has(token) && token.length >= 2) counts.set(token, (counts.get(token) || 0) + 1);
  });
  const topEntities = [...counts.entries()].sort((a, b) => b[1] - a[1]).slice(0, 5).map(([token, count]) => `${token} (${count})`).join(', ');
  return { json: { timestamp: new Date().toISOString(), input_row: $item(0).$node['Pick First SERP Pending'].json.row_number || '', keyword: $item(0).$node['Pick First SERP Pending'].json.keyword || '', position: index + 1, title: row.title || '', link: row.link || row.url || '', snippet: row.snippet || row.description || '', top_entities: topEntities, entity_count: counts.size, entity_theme: classifyTheme(text), mode: 'live' } };
});

