const text = $json.choices?.[0]?.message?.content || '';
const pickInput = $item(0).$node['Pick First SEO Pending'].json;
const grab = (name, next) => {
  const pattern = next ? new RegExp(`===\\s*${name}\\s*===([\\s\\S]*?)===\\s*${next}\\s*===`) : new RegExp(`===\\s*${name}\\s*===([\\s\\S]*)$`);
  const match = text.match(pattern);
  return match ? match[1].trim() : '';
};
const keyword = pickInput.keyword || '';
const image25 = `https://dummyimage.com/1200x675/f3f4f6/111827&text=${encodeURIComponent(keyword)}+25%25`;
const image50 = `https://dummyimage.com/1200x675/f3f4f6/111827&text=${encodeURIComponent(keyword)}+50%25`;
const image75 = `https://dummyimage.com/1200x675/f3f4f6/111827&text=${encodeURIComponent(keyword)}+75%25`;
const article = grab('ARTICLE', 'IMAGE_PROMPT_25');
const articleWithImages = [article, '', `[IMAGE_25] ${image25}`, '', `[IMAGE_50] ${image50}`, '', `[IMAGE_75] ${image75}`].join('\n');
return [{ json: { timestamp: new Date().toISOString(), input_row: pickInput.row_number || '', keyword, product: pickInput.product || '', scenario: pickInput.scenario || '', article, image_prompt_25: grab('IMAGE_PROMPT_25', 'IMAGE_PROMPT_50'), image_prompt_50: grab('IMAGE_PROMPT_50', 'IMAGE_PROMPT_75'), image_prompt_75: grab('IMAGE_PROMPT_75', 'QUALITY_NOTES'), article_with_images: articleWithImages, image_url_25: image25, image_url_50: image50, image_url_75: image75, quality_notes: grab('QUALITY_NOTES', 'IMPROVEMENT_POINTS'), improvement_points: grab('IMPROVEMENT_POINTS', 'REVISED_ARTICLE'), revised_article: grab('REVISED_ARTICLE'), output_folder: pickInput.output_folder || 'default', mode: 'live' } }];
